import time
import hashlib
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional
import anthropic

class BreakerState(Enum):
    CLOSED = "closed"
    OPEN = "open"
    HALF_OPEN = "half_open"

@dataclass
class CircuitBreaker:
    failure_threshold: int = 5
    recovery_timeout: float = 30.0
    _failures: int = 0
    _last_failure_time: float = 0.0
    _state: BreakerState = BreakerState.CLOSED

    @property
    def state(self) -> BreakerState:
        if self._state == BreakerState.OPEN:
            if time.monotonic() - self._last_failure_time > self.recovery_timeout:
                self._state = BreakerState.HALF_OPEN
        return self._state

    def record_success(self) -> None:
        self._failures = 0
        self._state = BreakerState.CLOSED

    def record_failure(self) -> None:
        self._failures += 1
        self._last_failure_time = time.monotonic()
        if self._failures >= self.failure_threshold:
            self._state = BreakerState.OPEN


@dataclass
class DegradationResult:
    content: str
    tier: int          # 0 = primary, 1 = degraded, 2 = cached, 3 = static
    model_used: str


class GracefulAgent:
    def __init__(self) -> None:
        self.client = anthropic.Anthropic()
        self.primary_breaker = CircuitBreaker()
        self.cache: dict[str, tuple[str, float]] = {}   # key -> (response, expiry)
        self.cache_ttl = 300.0  # 5 minutes

    def _cache_key(self, prompt: str) -> str:
        return hashlib.sha256(prompt.encode()).hexdigest()[:16]

    def _read_cache(self, prompt: str) -> Optional[str]:
        key = self._cache_key(prompt)
        if key in self.cache:
            response, expiry = self.cache[key]
            if time.monotonic() < expiry:
                return response
            del self.cache[key]
        return None

    def _write_cache(self, prompt: str, response: str) -> None:
        key = self._cache_key(prompt)
        self.cache[key] = (response, time.monotonic() + self.cache_ttl)

    def run(self, prompt: str) -> DegradationResult:
        # Tier 0: primary — full model
        if self.primary_breaker.state != BreakerState.OPEN:
            try:
                msg = self.client.messages.create(
                    model="claude-opus-4-5",
                    max_tokens=2048,
                    messages=[{"role": "user", "content": prompt}],
                )
                text = msg.content[0].text
                self.primary_breaker.record_success()
                self._write_cache(prompt, text)
                return DegradationResult(content=text, tier=0, model_used="claude-opus-4-5")
            except (anthropic.RateLimitError, anthropic.APIStatusError, anthropic.APITimeoutError) as exc:
                print(f"[tier-0 failure] {type(exc).__name__}: {exc}")
                self.primary_breaker.record_failure()

        # Tier 1: degraded — smaller model, no expensive tools
        try:
            msg = self.client.messages.create(
                model="claude-haiku-4-5",
                max_tokens=512,
                messages=[{"role": "user", "content": prompt}],
            )
            return DegradationResult(
                content=msg.content[0].text, tier=1, model_used="claude-haiku-4-5"
            )
        except Exception as exc:
            print(f"[tier-1 failure] {type(exc).__name__}: {exc}")

        # Tier 2: cached response
        cached = self._read_cache(prompt)
        if cached:
            return DegradationResult(content=cached, tier=2, model_used="cache")

        # Tier 3: static default
        return DegradationResult(
            content="Service temporarily unavailable. Please try again shortly.",
            tier=3,
            model_used="static",
        )


if __name__ == "__main__":
    agent = GracefulAgent()
    result = agent.run("Summarise the key principles of distributed systems.")
    print(f"[tier={result.tier}, model={result.model_used}]")
    print(result.content)
